function bindTaskSubRows(scope){bindLocationMenus(scope);scope.querySelectorAll('[data-sub-location-mode]').forEach(x=>{const row=x.closest('[data-subtask-row]'),menu=row.querySelector('.sub-location-menu');const update=()=>{menu.classList.toggle('hidden',x.value!=='locations');refreshSubtaskLocationTimes(row,scope)};x.onchange=update;update()});scope.querySelectorAll('[data-sub-cadence]').forEach(x=>{const row=x.closest('[data-subtask-row]'),weekly=row.querySelector('[data-sub-weekly]');const update=()=>{weekly.disabled=x.value==='monthly';if(x.value==='monthly')weekly.value=1};x.onchange=update;update()});scope.querySelectorAll('[data-remove-subtask]').forEach(b=>b.onclick=()=>b.closest('[data-subtask-row]').remove());let dragged=null;scope.querySelectorAll('[data-subtask-drag]').forEach(h=>{h.ondragstart=e=>{dragged=h.closest('[data-subtask-row]');dragged.classList.add('dragging-item');e.dataTransfer.effectAllowed='move'};h.ondragend=()=>{dragged?.classList.remove('dragging-item');dragged=null;scope.querySelectorAll('.drop-before,.drop-after').forEach(x=>x.classList.remove('drop-before','drop-after'))}});scope.querySelectorAll('[data-subtask-row]').forEach(row=>{row.ondragover=e=>{if(!dragged||row===dragged)return;e.preventDefault();scope.querySelectorAll('[data-subtask-row]').forEach(x=>x.classList.remove('drop-before','drop-after'));row.classList.add(e.clientY<row.getBoundingClientRect().top+row.offsetHeight/2?'drop-before':'drop-after')};row.ondrop=e=>{if(!dragged||row===dragged)return;e.preventDefault();const after=e.clientY>=row.getBoundingClientRect().top+row.offsetHeight/2;row.parentNode.insertBefore(dragged,after?row.nextSibling:row);scope.querySelectorAll('.drop-before,.drop-after').forEach(x=>x.classList.remove('drop-before','drop-after'))}})}
function bindTaskCards(){document.querySelectorAll('[data-task-handle]').forEach(h=>h.onclick=e=>e.stopPropagation());bindTaskCardDrag();document.querySelectorAll('[data-expand]').forEach(b=>b.onclick=()=>{store.expandedTaskKey=store.expandedTaskKey===b.dataset.expand?null:b.dataset.expand;renderTasks()});document.querySelectorAll('[data-del]').forEach(b=>b.onclick=async()=>{if(confirm('Delete this task and its calendar items?'))await actions.deleteTask(b.dataset.del)});document.querySelectorAll('[data-edit]').forEach(b=>b.onclick=()=>{const t=selectors.taskById(b.dataset.edit);const root=modal('Edit task',taskForm(t));bindTaskForm(root.querySelector('#taskForm'))})}

function bindTaskCardDrag(){let dragged=null;document.querySelectorAll('[data-task-drag]').forEach(card=>{card.ondragstart=e=>{if(e.target.closest('button,input,select,textarea')&&!e.target.closest('[data-task-handle]')){e.preventDefault();return}dragged=card;card.classList.add('dragging-item');e.dataTransfer.effectAllowed='move';e.dataTransfer.setData('text/plain',card.dataset.taskDrag)};card.ondragend=()=>{card.classList.remove('dragging-item');dragged=null;document.querySelectorAll('.drop-before,.drop-after').forEach(x=>x.classList.remove('drop-before','drop-after'))};card.ondragover=e=>{if(!dragged||card===dragged||card.dataset.taskLocation!==dragged.dataset.taskLocation)return;e.preventDefault();document.querySelectorAll('[data-task-drag]').forEach(x=>x.classList.remove('drop-before','drop-after'));card.classList.add(e.clientY<card.getBoundingClientRect().top+card.offsetHeight/2?'drop-before':'drop-after')};card.ondrop=async e=>{if(!dragged||card===dragged||card.dataset.taskLocation!==dragged.dataset.taskLocation)return;e.preventDefault();const after=e.clientY>=card.getBoundingClientRect().top+card.offsetHeight/2,moved=dragged.dataset.taskDrag,target=card.dataset.taskDrag;await actions.moveTask(moved,target,after);renderTasks()}})}
function renderCalendar(){const root=$('calendarTab'),m=store.data.meta.startMondayISO||isoDate(mondayOf(new Date()));root.innerHTML=`<div class="section-card"><h2>4-week calendar</h2><div class="calendar-controls"><div class="field"><label>Week 1 Monday<input id="startMonday" type="date" value="${m}"></label></div><button id="saveMonday" class="secondary-btn">Save date</button>${[0,1,2,3].map(w=>`<label class="check-chip"><input type="checkbox" data-week-vis="${w}" ${store.data.meta.weekVisibility[w]?'checked':''}>Week ${w+1}</label>`).join('')}</div></div>${[0,1,2,3].filter(w=>store.data.meta.weekVisibility[w]).map(weekHtml).join('')}`;$('saveMonday').onclick=()=>actions.setStartMonday($('startMonday').value);document.querySelectorAll('[data-week-vis]').forEach(x=>x.onchange=()=>actions.setWeekVisible(+x.dataset.weekVis,x.checked));bindCalendar()}
function weekHtml(w){const start=addDays(new Date((store.data.meta.startMondayISO||isoDate(mondayOf(new Date())))+'T00:00:00'),w*7);return `<div class="section-card"><div class="section-head"><h3>Week ${w+1} <span class="task-sub">${prettyDate(isoDate(start))}</span></h3><div class="button-row">${activeLocationId==='all'?[0,1,2,3].filter(x=>x!==w).map(x=>`<button class="mini-btn" data-copy="${w}_${x}">Copy to W${x+1}</button>`).join(''):''}</div></div><div class="calendar-grid">${DAY_NAMES.map((n,d)=>dayHtml(w,d,n,isoDate(addDays(start,d)))).join('')}</div></div>`}
function currentDayLocation(w,d){
  if(activeLocationId!=='all')return activeLocationId;
  const setting=selectors.daySetting(w,d), items=selectors.assignmentsFor(w,d);
  let locationId=setting.locationId||'';
  for(const item of items){if(item.type==='travel'&&item.locationId)locationId=item.locationId}
  return locationId;
}
function timeToMinutes(value){if(!value||!/^\d{2}:\d{2}$/.test(value))return null;const [h,m]=value.split(':').map(Number);return h*60+m}
function displayTime(total){if(total===null)return '';total=((total%1440)+1440)%1440;const h24=Math.floor(total/60),m=total%60,ampm=h24>=12?'PM':'AM',h=h24%12||12;return `${h}:${String(m).padStart(2,'0')} ${ampm}`}
function dayTimeline(items,startTime){let cursor=timeToMinutes(startTime);return items.map(item=>{const start=cursor;if(cursor!==null){if(item.type==='travel')cursor+=+item.travelMinutes||0;else if(item.type==='break')cursor+=+item.breakMinutes||0;else cursor+=selectors.assignmentMinutes(item)}return{item,start}})}
function dayHtml(w,d,n,date){
  const s=selectors.daySetting(w,d),allAssignments=selectors.assignmentsFor(w,d),as=activeLocationId==='all'?allAssignments:allAssignments.filter(x=>x.type==='task'&&x.locationId===activeLocationId),currentLoc=currentDayLocation(w,d),current=selectors.locationById(currentLoc);
  const taskTotal=as.filter(x=>x.type==='task').reduce((sum,x)=>sum+selectors.assignmentMinutes(x),0);
  const timeline=dayTimeline(as,s.startTime||'');
  const report=dayCopyReports.get(`${w}_${d}`);return `<div class="day-card ${activeLocationId!=='all'?'location-filtered-day':''}"><div class="day-title"><span>${n}</span><span class="day-title-actions">${activeLocationId==='all'?`<button type="button" class="day-copy-btn" data-copy-day="${w}_${d}" title="Copy this day">Copy</button>`:''}<span class="task-sub">${prettyDate(date)}</span></span></div>${report?copyReportHtml(report,`${w}_${d}`):''}<div class="day-total">Task total: ${formatDuration(taskTotal)}</div><div class="day-setup">${activeLocationId==='all'?`<select data-day-loc="${w}_${d}"><option value="">Start location…</option>${allLocations().map(l=>`<option value="${l.id}" ${s.locationId===l.id?'selected':''}>${esc(l.name)}</option>`).join('')}</select>`:`<div class="filtered-location-label">${esc(current?.name||'Selected location')}</div>`}<input data-day-time="${w}_${d}" type="time" value="${esc(s.startTime||'')}" title="Start time"></div><div class="day-items">${timeline.map((x,i)=>assignmentHtml(x.item,x.start,w,d,segmentForIndex(as,i))).join('')||'<div class="empty-note compact">No items.</div>'}</div><div class="current-location ${currentLoc?'':'muted'}">${currentLoc?`Current: ${esc(current?.name||'Location')}`:'Choose a start location'}</div><select data-picker="${w}_${d}" aria-label="Add task"></select>${activeLocationId==='all'?`<div class="travel-row"><select data-travel-loc="${w}_${d}" aria-label="Travel destination"><option value="">Travel to…</option>${allLocations().filter(l=>l.id!==currentLoc).map(l=>`<option value="${l.id}">${esc(l.name)}</option>`).join('')}</select><input data-travel-min="${w}_${d}" type="number" min="0" placeholder="min" aria-label="Travel minutes"><button class="mini-btn" data-travel="${w}_${d}">Go</button></div>`:''}${activeLocationId==='all'?`<div class="break-row"><input data-break-min="${w}_${d}" type="number" min="1" value="30" aria-label="Lunch break minutes"><button class="mini-btn" data-break="${w}_${d}">Add lunch</button></div>`:''}</div>`
}

function segmentForIndex(items,index){let segment=0;for(let i=0;i<index;i++)if(items[i].type==='travel')segment++;return segment}
function formatDuration(minutes){const h=Math.floor(minutes/60),m=minutes%60;if(!h)return `${m} min`;if(!m)return `${h} hr`;return `${h} hr ${m} min`}
function assignmentHtml(a,start,w,d,segment){const time=`<div class="assignment-time">${start===null?'':displayTime(start)}</div>`;if(a.type==='travel'){const l=selectors.locationById(a.locationId);return `<div class="assignment-row travel-boundary" data-calendar-item="${a.id}" data-calendar-day="${w}_${d}" data-calendar-segment="${segment}">${time}<div class="assignment travel"><div class="assignment-main"><div class="assignment-name">Travel to ${esc(l?.name||'location')}</div><div class="assignment-meta">${a.travelMinutes||0} minutes</div></div><button class="icon-btn" data-rm="${a.id}">×</button></div></div>`}if(a.type==='break'){return `<div class="assignment-row calendar-draggable" draggable="true" data-calendar-item="${a.id}" data-calendar-day="${w}_${d}" data-calendar-segment="${segment}">${time}<div class="assignment break"><span class="drag-handle calendar-drag-handle" title="Drag to reorder">⋮⋮</span><div class="assignment-main"><div class="assignment-name">Lunch break</div><div class="assignment-meta">${a.breakMinutes||0} minutes</div></div><button class="icon-btn" data-rm="${a.id}">×</button></div></div>`}const t=selectors.taskById(a.taskId),l=selectors.locationById(a.locationId),color=l?.color||'#94a3b8',subs=(a.subtaskIds||[]).map(id=>t?.subtasks?.find(x=>x.id===id)).filter(Boolean),eligibleSubs=t?selectors.eligibleSubtasks(t.id,a.locationId,a.weekIndex,a.id):[],canChooseSubs=subs.length>0||eligibleSubs.length>0;return `<div class="assignment-row calendar-draggable" draggable="true" data-calendar-item="${a.id}" data-calendar-day="${w}_${d}" data-calendar-segment="${segment}">${time}<div class="assignment task-assignment" style="--location-color:${esc(color)}"><span class="drag-handle calendar-drag-handle" title="Drag to reorder">⋮⋮</span><input type="checkbox" data-done="${a.id}" ${a.done?'checked':''}><button type="button" class="assignment-main assignment-edit-target" ${canChooseSubs?`data-edit-assignment-subs="${a.id}" title="Choose items"`:''}><div class="assignment-name">${esc(t?.name||'Missing task')}</div>${subs.length?`<div class="calendar-subtask-status assigned">${subs.length} item${subs.length===1?'':'s'} assigned</div><div class="calendar-subtask-names">${subs.map(x=>`${esc(x.name)} (${selectors.subtaskMinutes(t,x,a.locationId)}m)`).join(' • ')}</div>`:eligibleSubs.length?`<div class="calendar-subtask-status unassigned">Select items</div>`:''}</button><button class="icon-btn" data-rm="${a.id}">×</button></div></div>`}
function bindCalendar(){
  if(activeLocationId==='all')bindCalendarDrag();
  document.querySelectorAll('[data-day-loc]').forEach(x=>{x.onchange=async()=>{const [w,d]=x.dataset.dayLoc.split('_').map(Number);await actions.setDaySetting(w,d,{locationId:x.value});renderCalendar()}});
  document.querySelectorAll('[data-day-time]').forEach(x=>x.onchange=()=>{const [w,d]=x.dataset.dayTime.split('_').map(Number);actions.setDaySetting(w,d,{startTime:x.value})});
  document.querySelectorAll('[data-picker]').forEach(p=>{refreshPicker(p.dataset.picker);p.onchange=async()=>{if(!p.value)return;const k=p.dataset.picker,[w,d]=k.split('_').map(Number),loc=currentDayLocation(w,d),task=selectors.taskById(p.value);p.value='';if(!loc){toast('Choose a start location first.','error');return}p.disabled=true;try{await actions.scheduleTask(task.id,loc,w,d,[]);renderCalendar()}catch(e){p.disabled=false}}});
  document.querySelectorAll('[data-travel]').forEach(b=>b.onclick=async()=>{const k=b.dataset.travel,[w,d]=k.split('_').map(Number),loc=document.querySelector(`[data-travel-loc="${k}"]`).value,min=+document.querySelector(`[data-travel-min="${k}"]`).value;if(loc){await actions.addTravel(loc,w,d,min);renderCalendar()}});
  document.querySelectorAll('[data-break]').forEach(b=>b.onclick=async()=>{const k=b.dataset.break,[w,d]=k.split('_').map(Number),min=+document.querySelector(`[data-break-min="${k}"]`).value||30;await actions.addBreak(w,d,min);renderCalendar()});
  document.querySelectorAll('[data-done]').forEach(x=>x.onchange=()=>actions.toggleAssignment(x.dataset.done,x.checked));
  document.querySelectorAll('[data-rm]').forEach(x=>x.onclick=async()=>{await actions.deleteAssignment(x.dataset.rm);renderCalendar()});
  document.querySelectorAll('[data-edit-assignment-subs]').forEach(x=>x.onclick=()=>openAssignmentSubtaskPicker(x.dataset.editAssignmentSubs));
  document.querySelectorAll('[data-copy]').forEach(x=>x.onclick=async()=>{const [f,t]=x.dataset.copy.split('_').map(Number);if(!confirm(`Replace Week ${t+1} with a copy of Week ${f+1}?`))return;const original=x.innerHTML;x.disabled=true;x.innerHTML='<span class="spinner" aria-hidden="true"></span> Copying…';try{await actions.copyWeek(f,t);renderCalendar();toast(`Week ${t+1} copied.`,'good')}catch(e){x.disabled=false;x.innerHTML=original;toast(e.message||'Could not copy week.','error')}});document.querySelectorAll('[data-copy-day]').forEach(b=>b.onclick=()=>openCopyDayModal(...b.dataset.copyDay.split('_').map(Number)));document.querySelectorAll('[data-dismiss-copy-report]').forEach(b=>b.onclick=()=>{dayCopyReports.delete(b.dataset.dismissCopyReport);b.closest('.copy-report')?.remove()})
}


function copyReportHtml(report,key=''){const skipped=[...(report.skippedTasks||[]),...(report.skippedSubtasks||[]),...(report.skippedOther||[])];if(!skipped.length)return `<div class="copy-report success" title="Everything valid was copied"><span>Copied successfully</span><button type="button" class="copy-report-close" data-dismiss-copy-report="${key}" aria-label="Dismiss copy report" title="Dismiss">×</button></div>`;return `<details class="copy-report warning"><summary>${skipped.length} item${skipped.length===1?'':'s'} not copied</summary><button type="button" class="copy-report-close" data-dismiss-copy-report="${key}" aria-label="Dismiss copy report" title="Dismiss">×</button><div>${skipped.map(x=>`<span>${esc(x)}</span>`).join('')}</div></details>`}
function openCopyDayModal(fromW,fromD){const options=[];for(let w=0;w<4;w++)for(let d=0;d<5;d++)if(w!==fromW||d!==fromD)options.push(`<option value="${w}_${d}">Week ${w+1} — ${DAY_NAMES[d]}</option>`);const root=modal(`Copy ${DAY_NAMES[fromD]}`,`<p class="task-sub">Copies valid tasks, selected subtasks, lunch breaks, and the start time. The destination day will be replaced. Travel entries are not copied.</p><div class="form-grid"><div class="field"><label>Destination day<select id="copyDayTarget">${options.join('')}</select></label></div><div class="field"><label>Destination location<select id="copyDayLocation"><option value="">Choose location…</option>${selectors.locations().map(l=>`<option value="${l.id}">${esc(l.name)}</option>`).join('')}</select></label></div></div>`,`<button id="confirmCopyDay" class="primary-btn">Copy day</button>`);const target=root.querySelector('#copyDayTarget'),location=root.querySelector('#copyDayLocation'),button=root.querySelector('#confirmCopyDay');const syncDefault=()=>{const [w,d]=target.value.split('_').map(Number),existing=selectors.daySetting(w,d).locationId;location.value=existing||''};target.onchange=syncDefault;syncDefault();button.onclick=async()=>{if(!location.value){toast('Choose a destination location.','error');return}const [toW,toD]=target.value.split('_').map(Number);if(!confirm(`Replace Week ${toW+1} ${DAY_NAMES[toD]} with this copied day?`))return;button.disabled=true;const original=button.innerHTML;button.innerHTML='<span class="spinner" aria-hidden="true"></span> Copying…';try{const report=await actions.copyDay(fromW,fromD,toW,toD,location.value);dayCopyReports.set(`${toW}_${toD}`,report);closeModal();renderCalendar();const skipped=(report.skippedTasks?.length||0)+(report.skippedSubtasks?.length||0)+(report.skippedOther?.length||0);toast(skipped?`Day copied with ${skipped} skipped item${skipped===1?'':'s'}.`:'Day copied.','good')}catch(e){button.disabled=false;button.innerHTML=original;toast(e.message||'Could not copy day.','error')}}}

function bindCalendarDrag(){let dragged=null;const clear=()=>document.querySelectorAll('.drop-before,.drop-after,.drop-zone-active').forEach(x=>x.classList.remove('drop-before','drop-after','drop-zone-active'));document.querySelectorAll('.calendar-draggable').forEach(row=>{row.ondragstart=e=>{if(e.target.closest('button,input,select')&&!e.target.closest('.calendar-drag-handle')){e.preventDefault();return}dragged=row;row.classList.add('dragging-item');e.dataTransfer.effectAllowed='move';document.querySelectorAll(`.calendar-draggable[data-calendar-day="${row.dataset.calendarDay}"][data-calendar-segment="${row.dataset.calendarSegment}"]`).forEach(x=>x.classList.add('drop-zone-active'))};row.ondragend=()=>{row.classList.remove('dragging-item');dragged=null;clear()};row.ondragover=e=>{if(!dragged||row===dragged||row.dataset.calendarDay!==dragged.dataset.calendarDay||row.dataset.calendarSegment!==dragged.dataset.calendarSegment)return;e.preventDefault();document.querySelectorAll('.drop-before,.drop-after').forEach(x=>x.classList.remove('drop-before','drop-after'));row.classList.add(e.clientY<row.getBoundingClientRect().top+row.offsetHeight/2?'drop-before':'drop-after')};row.ondrop=async e=>{if(!dragged||row===dragged||row.dataset.calendarDay!==dragged.dataset.calendarDay||row.dataset.calendarSegment!==dragged.dataset.calendarSegment)return;e.preventDefault();const after=e.clientY>=row.getBoundingClientRect().top+row.offsetHeight/2;row.parentNode.insertBefore(dragged,after?row.nextSibling:row);const [w,d]=row.dataset.calendarDay.split('_').map(Number),ids=[...row.closest('.day-items').querySelectorAll('[data-calendar-item]')].map(x=>x.dataset.calendarItem);clear();await actions.reorderAssignments(w,d,ids);renderCalendar()}})}
function refreshPicker(k){const [w,d]=k.split('_').map(Number),loc=currentDayLocation(w,d),p=document.querySelector(`[data-picker="${k}"]`);if(!p)return;const ts=loc?selectors.tasksForLocation(loc).filter(t=>selectors.weeklyAssignedCount(t.id,loc,w)<t.weeklyTarget):[];p.innerHTML=`<option value="">${loc?'Add task…':'Choose start location first'}</option>${ts.map(t=>`<option value="${t.id}">${esc(t.name)} (${selectors.weeklyAssignedCount(t.id,loc,w)}/${t.weeklyTarget})</option>`).join('')}`;p.disabled=!loc||!ts.length}
function openAssignmentSubtaskPicker(assignmentId){
  const a=selectors.assignments().find(x=>x.id===assignmentId),task=a&&selectors.taskById(a.taskId);
  if(!a||!task)return;
  const eligible=selectors.eligibleSubtasks(task.id,a.locationId,a.weekIndex,a.id),selected=new Set(a.subtaskIds||[]);
  if(!eligible.length&&!selected.size){toast('No items are available for this location and period.','error');return}
  const choices=eligible.map(s=>`<label><input type="checkbox" data-choose-subtask value="${s.id}" ${selected.has(s.id)?'checked':''}><span><b>${esc(s.name)}</b><small>${s.cadence==='monthly'?'Once in this 4-week planner':`${s.weeklyTarget||1}x each week`} • ${selectors.subtaskMinutes(task,s,a.locationId)} min</small></span></label>`).join('');
  const root=modal(task.name,`<p class="task-sub">Choose the items for this specific week. The calendar task can remain unassigned while you build and copy your schedule.</p><div class="subtask-choice-toolbar"><button id="selectAllEligible" type="button" class="mini-btn">Select all available</button><button id="clearSelectedItems" type="button" class="mini-btn">Clear</button></div><div class="subtask-choice-list">${choices||'<div class="empty-note">No available items.</div>'}</div>`,`<button id="saveAssignmentSubtasks" class="primary-btn">Save items</button>`);
  root.querySelector('#selectAllEligible').onclick=()=>root.querySelectorAll('[data-choose-subtask]').forEach(x=>x.checked=true);
  root.querySelector('#clearSelectedItems').onclick=()=>root.querySelectorAll('[data-choose-subtask]').forEach(x=>x.checked=false);
  root.querySelector('#saveAssignmentSubtasks').onclick=async()=>{const ids=[...root.querySelectorAll('[data-choose-subtask]:checked')].map(x=>x.value);root.querySelector('#saveAssignmentSubtasks').disabled=true;try{await actions.updateAssignmentSubtasks(a.id,ids);closeModal();renderCalendar()}catch(e){root.querySelector('#saveAssignmentSubtasks').disabled=false}};
}
function renderLocations(){const r=$('locationsTab');r.innerHTML=`<div class="section-card"><h2>Locations</h2><form id="locForm" class="button-row"><input id="locName" placeholder="Location name"><input id="locColor" type="color" value="#2563eb"><button class="primary-btn">Add</button></form></div><div class="section-card"><div class="loc-list">${visibleLocations().map(l=>`<div class="loc-card"><div class="location-title"><input class="location-color-picker" type="color" value="${esc(l.color)}" data-loc-color="${l.id}" title="Choose calendar color"><span>${esc(l.name)}</span></div>${progress(l)}<div class="detail-actions"><button class="mini-btn" data-loc-edit="${l.id}">Rename</button><button class="danger-btn" data-loc-del="${l.id}">Archive</button></div></div>`).join('')}</div></div>`;$('locForm').onsubmit=async e=>{e.preventDefault();await actions.createLocation($('locName').value,$('locColor').value)};document.querySelectorAll('[data-loc-color]').forEach(x=>x.onchange=()=>actions.updateLocation(x.dataset.locColor,{color:x.value}));document.querySelectorAll('[data-loc-edit]').forEach(b=>b.onclick=async()=>{const l=selectors.locationById(b.dataset.locEdit),name=prompt('Location name',l.name);if(name)await actions.updateLocation(l.id,{name})});document.querySelectorAll('[data-loc-del]').forEach(b=>b.onclick=()=>confirm('Archive this location?')&&actions.deleteLocation(b.dataset.locDel))}
function renderUnfinished(){const r=$('unfinishedTab'),today=new Date();today.setHours(0,0,0,0);const start=new Date((store.data.meta.startMondayISO||isoDate(mondayOf(new Date())))+'T00:00:00');const items=selectors.assignments().filter(a=>a.type==='task'&&locationVisible(a.locationId)&&!a.done&&addDays(start,a.weekIndex*7+a.dayIndex)<today);r.innerHTML=`<div class="section-card"><h2>Unfinished tasks</h2><p class="task-sub">Past scheduled items that are not checked off.</p>${items.map(a=>{const t=selectors.taskById(a.taskId),l=selectors.locationById(a.locationId),date=isoDate(addDays(start,a.weekIndex*7+a.dayIndex));return `<div class="progress-row"><div><b>${esc(t?.name||'Missing task')}</b><div class="task-sub">${esc(l?.name||'')} • ${prettyDate(date)}</div></div><button class="mini-btn" data-finish="${a.id}">Mark done</button></div>`}).join('')||'<div class="empty-note">Nothing unfinished.</div>'}</div>`;document.querySelectorAll('[data-finish]').forEach(b=>b.onclick=()=>actions.toggleAssignment(b.dataset.finish,true))}
let trackedExpandedGroup='';
const trackedExpandedLocations=new Map();
let trackedExpandedItem='';
const TRACKED_FIELD_TYPES=[['text','Short text'],['textarea','Long notes'],['number','Number'],['toggle','Yes / No'],['choice','Choice'],['date','Date'],['datedAction','Date with action + color threshold'],['eventState','Current state + event history']];
function displayShortDate(v){if(!v)return 'Not set';const [y,m,d]=String(v).slice(0,10).split('-');return y&&m&&d?`${m}/${d}/${String(y).slice(-2)}`:String(v)}
function trackedAge(field){if(field.type!=='datedAction'||!field.value)return null;const start=new Date(`${String(field.value).slice(0,10)}T12:00:00`);if(Number.isNaN(start.getTime()))return null;const days=Math.max(0,Math.floor((Date.now()-start.getTime())/86400000)),limit=Math.max(1,+field.thresholdDays||30),ratio=Math.min(1,days/limit),hue=Math.round(120*(1-ratio));return{days,limit,ratio,color:`hsl(${hue} 72% 43%)`}}
function trackedUrgency(t){return t.fields.map(trackedAge).filter(Boolean).sort((a,b)=>b.ratio-a.ratio)[0]||null}
function trackedFieldControl(t,f){const base=`data-track-task="${t.id}" data-track-field="${f.id}"`,hist=(f.history||[]).slice(0,5);if(f.type==='toggle'){const yesEmoji=f.yesEmoji||'✅',noEmoji=f.noEmoji||'❌',value=!!f.value;return `<div class="tracked-boolean-slider" role="group" aria-label="${esc(f.label)}"><button type="button" class="tracked-boolean-option ${!value?'active':''}" data-track-toggle="${t.id}|${f.id}|false" aria-pressed="${!value}"><span class="tracked-boolean-emoji">${esc(noEmoji)}</span><span>No</span></button><button type="button" class="tracked-boolean-option ${value?'active':''}" data-track-toggle="${t.id}|${f.id}|true" aria-pressed="${value}"><span class="tracked-boolean-emoji">${esc(yesEmoji)}</span><span>Yes</span></button></div>`};if(f.type==='textarea')return `<textarea ${base} rows="3">${esc(f.value||'')}</textarea>`;if(f.type==='choice')return `<select ${base}><option value="">Choose…</option>${(f.options||[]).map(o=>`<option ${String(f.value)===o?'selected':''}>${esc(o)}</option>`).join('')}</select>`;if(f.type==='date')return `<input ${base} type="date" value="${esc(f.value||'')}"><div class="tracked-date-display">${displayShortDate(f.value)}</div>`;if(f.type==='datedAction'){const age=trackedAge(f);return `<div class="tracked-action-field">${age?`<div class="tracked-age-bar"><span style="width:${Math.round(age.ratio*100)}%;background:${age.color}"></span></div><div class="tracked-age-text"><b>${displayShortDate(f.value)}</b><span>${age.days} of ${age.limit} days</span></div>`:`<div class="tracked-date-display">Not set</div>`}<div class="tracked-action-row"><button type="button" class="secondary-btn" data-track-today="${t.id}|${f.id}">${esc(f.actionLabel||'Set to today')}</button><input ${base} type="date" value="${esc(f.value||'')}" aria-label="Choose date"></div></div>`}if(f.type==='eventState')return `<div class="tracked-event-state"><select ${base}><option value="">Not set</option>${(f.states||[]).map(o=>`<option ${String(f.value)===o?'selected':''}>${esc(o)}</option>`).join('')}</select><div class="tracked-event-buttons">${(f.eventButtons||[]).map(a=>`<button type="button" class="mini-btn" data-track-event="${t.id}|${f.id}|${encodeURIComponent(a)}">${esc(a)}</button>`).join('')}</div>${hist.length?`<details><summary>Recent history</summary>${hist.map(h=>`<div class="tracked-history-row"><b>${esc(h.action)}</b><span>${displayShortDate(h.date)}</span>${h.note?`<small>${esc(h.note)}</small>`:''}</div>`).join('')}</details>`:''}</div>`;return `<input ${base} type="${f.type==='number'?'number':'text'}" value="${esc(f.value??'')}">`}
function trackedItemRow(t){const open=trackedExpandedItem===t.id,urgent=trackedUrgency(t),toggleBadges=t.fields.filter(f=>f.type==='toggle').map(f=>`<span class="tracked-toggle-badge" title="${esc(f.label)}: ${f.value?'Yes':'No'}">${esc(f.value?(f.yesEmoji||'✅'):(f.noEmoji||'❌'))}</span>`).join('');return `<div class="tracked-item ${open?'open':''}" style="--tracked-status:${urgent?.color||'#98a2b3'}"><button class="tracked-item-head" data-track-item-expand="${t.id}"><span class="tracked-status-dot"></span><span class="tracked-item-name">${esc(t.title)}${toggleBadges?`<span class="tracked-toggle-badges">${toggleBadges}</span>`:''}</span>${urgent?`<span class="tracked-urgency">${urgent.days}/${urgent.limit} days</span>`:'<span class="tracked-urgency muted">No date</span>'}<span class="accordion-chevron">⌄</span></button>${open?`<div class="tracked-item-body">${t.fields.map(f=>`<div class="field tracked-field"><label>${esc(f.label)}</label>${trackedFieldControl(t,f)}</div>`).join('')||'<div class="empty-note">No fields configured.</div>'}<div class="tracked-card-actions"><button class="secondary-btn" data-track-log="${t.id}" title="View and correct the activity log">🧾 Log</button><button class="secondary-btn" data-track-stats="${t.id}" title="View change statistics">📊 Stats</button><button class="danger-btn" data-track-del="${t.id}">Delete item</button></div></div>`:''}</div>`}
function trackedLocationPanel(groupKey,locationId,list){const location=locationId==='all'?null:selectors.locationById(locationId),name=locationId==='all'?'All locations':location?.name||'Unknown location',open=trackedExpandedLocations.get(groupKey)===locationId,urgent=list.map(trackedUrgency).filter(Boolean).sort((a,b)=>b.ratio-a.ratio)[0];return `<div class="tracked-location ${open?'open':''}"><button class="tracked-location-head" data-track-location="${encodeURIComponent(groupKey)}|${encodeURIComponent(locationId)}"><span>${esc(name)}</span><span class="tracked-location-summary">${list.length} item${list.length===1?'':'s'}${urgent?` • ${urgent.days}/${urgent.limit} days`:''}</span><span class="accordion-chevron">⌄</span></button>${open?`<div class="tracked-location-items">${list.map(trackedItemRow).join('')}</div>`:''}</div>`}
function renderTracked(){const r=$('trackedTab'),items=selectors.trackedTasks().filter(t=>activeLocationId==='all'||t.locationId===activeLocationId||t.locationId==='all'),groups=[...new Set(items.map(t=>t.groupTitle||t.title))];r.innerHTML=`<div class="section-card compact-section-head"><div class="section-head"><div><h2>Tracked Tasks</h2><p>Flexible records created manually or from an existing task and its subtasks.</p></div><button id="newTracked" class="primary-btn">Add tracked task</button></div></div>${groups.map(g=>{const list=items.filter(t=>(t.groupTitle||t.title)===g),open=trackedExpandedGroup===g,locations=[...new Set(list.map(t=>t.locationId||'all'))],urgent=list.map(trackedUrgency).filter(Boolean).sort((a,b)=>b.ratio-a.ratio)[0];return `<div class="section-card tracked-group ${open?'open':''}"><button class="tracked-group-head" data-track-group="${encodeURIComponent(g)}"><span><b>${esc(g)}</b><small>${list.length} tracked item${list.length===1?'':'s'}${urgent?` • most urgent ${urgent.days}/${urgent.limit} days`:''}</small></span><span class="accordion-chevron">⌄</span></button>${open?`<div class="tracked-group-body"><div class="tracked-location-columns">${locations.map(lid=>trackedLocationPanel(g,lid,list.filter(t=>(t.locationId||'all')===lid))).join('')}</div></div>`:''}</div>`}).join('')||'<div class="section-card"><div class="empty-note">No tracked tasks.</div></div>'}`;$('newTracked').onclick=openTrackedBuilder;document.querySelectorAll('[data-track-group]').forEach(b=>b.onclick=()=>{const g=decodeURIComponent(b.dataset.trackGroup);if(trackedExpandedGroup===g){trackedExpandedGroup='';trackedExpandedItem=''}else{trackedExpandedGroup=g;trackedExpandedItem=''}renderTracked()});document.querySelectorAll('[data-track-location]').forEach(b=>b.onclick=()=>{const [rawG,rawL]=b.dataset.trackLocation.split('|'),g=decodeURIComponent(rawG),lid=decodeURIComponent(rawL);trackedExpandedLocations.set(g,trackedExpandedLocations.get(g)===lid?'':lid);trackedExpandedItem='';renderTracked()});document.querySelectorAll('[data-track-item-expand]').forEach(b=>b.onclick=()=>{trackedExpandedItem=trackedExpandedItem===b.dataset.trackItemExpand?'':b.dataset.trackItemExpand;renderTracked()});document.querySelectorAll('[data-track-del]').forEach(b=>b.onclick=()=>confirm('Delete this tracked item?')&&actions.deleteTracked(b.dataset.trackDel));document.querySelectorAll('[data-track-log]').forEach(b=>b.onclick=()=>openTrackedLog(b.dataset.trackLog));document.querySelectorAll('[data-track-stats]').forEach(b=>b.onclick=()=>openTrackedStats(b.dataset.trackStats));document.querySelectorAll('[data-track-field]').forEach(x=>x.onchange=async()=>runTrackedSave(x,async()=>{const t=selectors.trackedTaskById(x.dataset.trackTask),f=t?.fields.find(v=>v.id===x.dataset.trackField),value=x.value;await actions.saveTrackedField(t.id,f.id,value,(f.type==='eventState'||f.type==='datedAction')?{action:'Updated',value,date:new Date().toISOString().slice(0,10)}:null)}));document.querySelectorAll('[data-track-toggle]').forEach(b=>b.onclick=async()=>runTrackedSave(b,async()=>{const [tid,fid,raw]=b.dataset.trackToggle.split('|');await actions.saveTrackedField(tid,fid,raw==='true',{action:raw==='true'?'Set to Yes':'Set to No',value:raw==='true',date:new Date().toISOString().slice(0,10)})}));document.querySelectorAll('[data-track-today]').forEach(b=>b.onclick=async()=>runTrackedSave(b,async()=>{const [tid,fid]=b.dataset.trackToday.split('|'),t=selectors.trackedTaskById(tid),f=t?.fields.find(v=>v.id===fid),today=new Date().toISOString().slice(0,10);await actions.saveTrackedField(tid,fid,today,{action:f.actionLabel||'Set to today',value:today,date:today})}));document.querySelectorAll('[data-track-event]').forEach(b=>b.onclick=async()=>{const [tid,fid,raw]=b.dataset.trackEvent.split('|'),action=decodeURIComponent(raw),t=selectors.trackedTaskById(tid),f=t?.fields.find(v=>v.id===fid);const note=prompt(`${action}${f.label?` — ${f.label}`:''}\nOptional note:`);if(note===null)return;let value=f.value;if((f.states||[]).includes(action))value=action;await runTrackedSave(b,()=>actions.saveTrackedField(tid,fid,value,{action,value,date:new Date().toISOString().slice(0,10),note}))})}

async function runTrackedSave(source,work){const item=source?.closest?.('.tracked-item'),pill=document.createElement('div');pill.className='tracked-saving-pill';pill.innerHTML='<span class="spinner"></span><span>Saving…</span>';item?.appendChild(pill);item?.classList.add('tracked-is-saving');item?.querySelectorAll('button,input,select,textarea').forEach(el=>el.disabled=true);try{await work();renderTracked()}catch(e){console.error(e);item?.classList.remove('tracked-is-saving');pill.remove()}}
function trackedLogRow(l){return`<div class="tracked-log-row"><div class="tracked-log-date">${displayShortDate(l.changedDate||String(l.changedAt).slice(0,10))}</div><div class="tracked-log-detail"><b>${esc(l.fieldLabel||'Field')}</b><span>${esc(l.action||'Updated')}: ${esc(statsValue(l.previousValue))} → ${esc(statsValue(l.newValue))}</span>${l.note?`<small>${esc(l.note)}</small>`:''}</div><button type="button" class="danger-btn tracked-log-delete" data-delete-track-log="${l.id}">Delete</button></div>`}
async function openTrackedLog(id){const t=selectors.trackedTaskById(id);if(!t)return;const root=modal(`${t.title} — Activity Log`,`<div id="trackedLogBody" class="tracked-stats-loading">Loading activity log…</div>`);let logs=[];try{logs=await loadTrackedLogs(id)}catch(e){console.error(e)}if(!logs.length)logs=(t.changeLog||[]).slice();const draw=()=>{const body=root.querySelector('#trackedLogBody');body.className='tracked-log-list';body.innerHTML=logs.length?logs.map(trackedLogRow).join(''):'<div class="empty-note">No activity has been recorded.</div>';body.querySelectorAll('[data-delete-track-log]').forEach(b=>b.onclick=async()=>{if(!confirm('Delete this log entry? It will no longer be included in Stats.'))return;const row=b.closest('.tracked-log-row');row.classList.add('tracked-log-deleting');b.disabled=true;b.innerHTML='<span class="spinner"></span>';try{await actions.deleteTrackedLog(id,b.dataset.deleteTrackLog);logs=logs.filter(x=>x.id!==b.dataset.deleteTrackLog);draw();toast('Log entry deleted.','good')}catch(e){row.classList.remove('tracked-log-deleting');b.disabled=false;b.textContent='Delete'}})};draw()}

function statsValue(v){if(v===true)return'Yes';if(v===false)return'No';if(v===null||typeof v==='undefined'||v==='')return'Not set';return String(v)}
function daysBetween(a,b){const x=new Date(`${String(a).slice(0,10)}T12:00:00`),y=new Date(`${String(b).slice(0,10)}T12:00:00`);return Number.isNaN(x.getTime())||Number.isNaN(y.getTime())?null:Math.round(Math.abs(y-x)/86400000)}
function summarizeTrackedLogs(t,logs){const byField=new Map();logs.forEach(l=>{const key=l.fieldId||l.fieldLabel||'unknown';if(!byField.has(key))byField.set(key,[]);byField.get(key).push(l)});const rows=t.fields.map(f=>{const list=(byField.get(f.id)||[]).sort((a,b)=>String(a.changedAt).localeCompare(String(b.changedAt))),dates=list.map(x=>x.changedDate||String(x.changedAt).slice(0,10)).filter(Boolean),intervals=[];for(let i=1;i<dates.length;i++){const d=daysBetween(dates[i-1],dates[i]);if(d!==null&&d>0)intervals.push(d)}const avg=intervals.length?Math.round(intervals.reduce((a,b)=>a+b,0)/intervals.length):null;let insight='No changes recorded yet.';if(list.length){insight=`${list.length} change${list.length===1?'':'s'} recorded`;if(avg)insight+=` • about every ${avg} day${avg===1?'':'s'}`;if(f.type==='toggle'){const yes=list.filter(x=>x.newValue===true||x.newValue==='true').length,no=list.filter(x=>x.newValue===false||x.newValue==='false').length;insight+=` • Yes ${yes} / No ${no}`}}return`<div class="tracked-stat-field"><div><b>${esc(f.label)}</b><span>${esc(insight)}</span></div><strong>${esc(statsValue(f.value))}</strong></div>`}).join('');const recent=logs.slice(0,12).map(l=>`<div class="tracked-stat-log"><span>${displayShortDate(l.changedDate||String(l.changedAt).slice(0,10))}</span><div><b>${esc(l.fieldLabel||'Field')}</b><small>${esc(l.action||'Updated')}: ${esc(statsValue(l.previousValue))} → ${esc(statsValue(l.newValue))}${l.note?` • ${esc(l.note)}`:''}</small></div></div>`).join('');return`<div class="tracked-stats-summary"><div class="tracked-stat-callout"><b>${logs.length}</b><span>Total saved changes</span></div><div class="tracked-stat-callout"><b>${logs[0]?displayShortDate(logs[0].changedDate||String(logs[0].changedAt).slice(0,10)):'—'}</b><span>Most recent change</span></div></div><h3>Field summary</h3><div class="tracked-stat-fields">${rows}</div><h3>Recent activity</h3><div class="tracked-stat-logs">${recent||'<div class="empty-note">No activity has been recorded yet. New changes will appear here.</div>'}</div>`}
async function openTrackedStats(id){const t=selectors.trackedTaskById(id);if(!t)return;const root=modal(`${t.title} — Stats`,`<div id="trackedStatsBody" class="tracked-stats-loading">Loading saved change history…</div>`);let logs=[];try{logs=await loadTrackedLogs(id)}catch(e){console.error(e)}if(!logs.length)logs=(t.changeLog||[]).slice();root.querySelector('#trackedStatsBody').className='';root.querySelector('#trackedStatsBody').innerHTML=summarizeTrackedLogs(t,logs)}

