function updateTrackedFieldSettings(row){const type=row.querySelector('[data-f-type]').value,box=row.querySelector('[data-f-settings]');box.innerHTML=type==='toggle'?`<label>No emoji<input data-f-no-emoji value="❌" maxlength="8" placeholder="❌"></label><label>Yes emoji<input data-f-yes-emoji value="✅" maxlength="8" placeholder="✅"></label>`:type==='choice'?`<label>Choices<input data-f-options placeholder="Good, Fair, Poor"></label>`:type==='datedAction'?`<label>Button text<input data-f-action value="Set to today"></label><label>Days until red<input data-f-threshold type="number" min="1" value="30"></label>`:type==='eventState'?`<label>Possible current states<input data-f-states placeholder="Present, Not present"></label><label>Event buttons<input data-f-events placeholder="Added, Died, Removed"></label>`:''}
function openTrackedBuilder(){const tasks=selectors.tasks().filter(t=>(t.subtasks||[]).some(s=>!s.archived));const root=modal('Add tracked task',`<form id="trackedForm" class="tracked-builder"><div class="form-grid"><div class="field"><label>Create from<select id="trackedSource"><option value="manual">Manual item</option><option value="task">Existing task + subtasks</option></select></label></div><div class="field wide"><label>Tracker name<input id="trackedTitle" required placeholder="Fish Tanks"></label></div><div id="manualTrackedSettings" class="field"><label>Location<select id="trackedLoc"><option value="all">All locations</option>${selectors.locations().map(l=>`<option value="${l.id}">${esc(l.name)}</option>`).join('')}</select></label></div><div id="taskTrackedSettings" class="field full hidden"><label>Existing task<select id="trackedTaskSource"><option value="">Choose task</option>${tasks.map(t=>`<option value="${t.id}">${esc(t.name)}</option>`).join('')}</select></label><div id="trackedSubtaskPreview" class="tracked-source-preview"></div></div></div><div class="tracked-builder-heading"><h3>Fields</h3><button id="addTrackedField" type="button" class="secondary-btn">Add field</button></div><div id="trackedBuilderFields">${trackedFieldRow(0)}</div><button class="primary-btn">Create tracked task</button></form>`);const source=root.querySelector('#trackedSource'),manual=root.querySelector('#manualTrackedSettings'),taskSettings=root.querySelector('#taskTrackedSettings'),taskSelect=root.querySelector('#trackedTaskSource'),preview=root.querySelector('#trackedSubtaskPreview'),fields=root.querySelector('#trackedBuilderFields');const bindRows=()=>fields.querySelectorAll('[data-builder-field]').forEach(row=>{row.querySelector('[data-f-type]').onchange=()=>updateTrackedFieldSettings(row);row.querySelector('.tracked-remove-field').onclick=()=>{if(fields.children.length>1)row.remove()};updateTrackedFieldSettings(row)});bindRows();root.querySelector('#addTrackedField').onclick=()=>{fields.insertAdjacentHTML('beforeend',trackedFieldRow(fields.children.length));bindRows()};source.onchange=()=>{const useTask=source.value==='task';manual.classList.toggle('hidden',useTask);taskSettings.classList.toggle('hidden',!useTask)};taskSelect.onchange=()=>{const t=selectors.taskById(taskSelect.value);if(!t){preview.innerHTML='';return}const rows=[];(t.subtasks||[]).filter(s=>!s.archived).forEach(s=>{const locIds=s.locationMode==='locations'?s.locationIds:(t.appliesTo==='locations'?t.locationIds:selectors.locations().map(l=>l.id));(locIds.length?locIds:['all']).forEach(lid=>rows.push(`<label><input type="checkbox" data-source-sub="${s.id}" data-source-loc="${lid}" checked> ${esc(s.name)}${lid!=='all'?` — ${esc(selectors.locationById(lid)?.name||'')}`:''}</label>`))});preview.innerHTML=rows.join('')||'<div class="empty-note">This task has no active subtasks.</div>'};root.querySelector('#trackedForm').onsubmit=async e=>{e.preventDefault();const definitions=[...fields.querySelectorAll('[data-builder-field]')].map(row=>{const type=row.querySelector('[data-f-type]').value;return{id:uid('field'),label:row.querySelector('[data-f-label]').value.trim(),type,value:type==='toggle'?false:'',yesEmoji:row.querySelector('[data-f-yes-emoji]')?.value.trim()||'✅',noEmoji:row.querySelector('[data-f-no-emoji]')?.value.trim()||'❌',options:(row.querySelector('[data-f-options]')?.value||'').split(',').map(x=>x.trim()).filter(Boolean),actionLabel:row.querySelector('[data-f-action]')?.value.trim()||'Set to today',thresholdDays:+row.querySelector('[data-f-threshold]')?.value||30,colorEnabled:true,states:(row.querySelector('[data-f-states]')?.value||'').split(',').map(x=>x.trim()).filter(Boolean),eventButtons:(row.querySelector('[data-f-events]')?.value||'').split(',').map(x=>x.trim()).filter(Boolean),history:[]}});const groupTitle=root.querySelector('#trackedTitle').value.trim();if(source.value==='manual'){await actions.createTracked({title:groupTitle,groupTitle,locationId:root.querySelector('#trackedLoc').value,fields:definitions})}else{const task=selectors.taskById(taskSelect.value);if(!task)throw Error('Choose an existing task.');const selected=[...preview.querySelectorAll('[data-source-sub]:checked')];if(!selected.length)throw Error('Choose at least one subtask.');await actions.createTrackedBatch(selected.map(x=>{const sub=task.subtasks.find(s=>s.id===x.dataset.sourceSub);return{title:sub.name,groupTitle,locationId:x.dataset.sourceLoc,sourceTaskId:task.id,sourceSubtaskId:sub.id,fields:definitions.map(f=>({...f,id:uid('field'),history:[]}))}}))}closeModal();renderTracked();toast('Tracked task created.','good')}}
async function openHistory(){if(!store.loaded)return;const h=await loadHistory();modal('Save history',`<button id="exportBackup" class="secondary-btn">Download JSON backup</button>${h.map((x,i)=>`<div class="history-item"><div><b>${esc(x.reason||'Snapshot')}</b><div class="task-sub">${x.createdAt?.toDate?x.createdAt.toDate().toLocaleString():'Saved snapshot'}</div></div><button class="mini-btn" data-restore="${i}">Restore</button></div>`).join('')||'<div class="empty-note">No history.</div>'}`);$('exportBackup').onclick=()=>downloadJson('campus-cares-backup.json',store.data);document.querySelectorAll('[data-restore]').forEach(b=>b.onclick=async()=>{if(confirm('Restore this snapshot?')){await actions.restoreHistory(h[+b.dataset.restore]);closeModal();render()}})}


const issueExpanded=new Set();
const ISSUE_STATUSES=['Documented','Solution Decided','Materials Required','In-Progress','Completed','Dismiss'];
function issueAssigneeRows(values=['']){return values.map((v,i)=>`<div class="issue-assignee-row"><input data-issue-assignee value="${esc(v)}" placeholder="Name"><button type="button" class="mini-btn issue-remove-person" aria-label="Remove person">−</button>${i===values.length-1&&String(v).trim()?'<button type="button" class="mini-btn issue-add-person" aria-label="Add another person">+</button>':''}</div>`).join('')}
function bindIssueAssignees(root){const box=root.querySelector('[data-issue-assignees]');if(!box)return;const refreshButtons=()=>{const rows=[...box.querySelectorAll('.issue-assignee-row')];rows.forEach((row,i)=>{row.querySelector('.issue-add-person')?.remove();if(i===rows.length-1&&row.querySelector('[data-issue-assignee]')?.value.trim()){const add=document.createElement('button');add.type='button';add.className='mini-btn issue-add-person';add.setAttribute('aria-label','Add another person');add.textContent='+';add.onclick=()=>{box.insertAdjacentHTML('beforeend',issueAssigneeRows(['']));bindRows();box.querySelectorAll('[data-issue-assignee]')[box.querySelectorAll('[data-issue-assignee]').length-1]?.focus()};row.appendChild(add)}})};const bindRows=()=>{box.querySelectorAll('[data-issue-assignee]').forEach(input=>{input.oninput=refreshButtons});box.querySelectorAll('.issue-remove-person').forEach(b=>b.onclick=()=>{const rows=box.querySelectorAll('.issue-assignee-row');if(rows.length===1){const input=b.closest('.issue-assignee-row').querySelector('[data-issue-assignee]');input.value='';input.focus()}else b.closest('.issue-assignee-row').remove();refreshButtons()});refreshButtons()};bindRows()}
function issueCard(x){const open=issueExpanded.has(x.id),loc=x.locationId==='all'?null:selectors.locationById(x.locationId);return `<div class="issue-card ${open?'open':''}" data-issue-card="${x.id}"><button class="issue-card-head" data-issue-expand="${x.id}"><span>${esc(x.name)}</span><span class="issue-status-badge">${esc(x.status)}</span></button>${open?`<div class="issue-card-body"><div class="issue-meta"><span>${x.locationId==='all'?'All locations':esc(loc?.name||'No location')}</span>${x.assignedTo.length?`<span>Assigned: ${x.assignedTo.map(esc).join(', ')}</span>`:''}</div><p>${esc(x.description).replace(/\n/g,'<br>')}</p>${x.photoUrl?`<a href="${esc(x.photoUrl)}" target="_blank" rel="noopener"><img class="issue-photo" src="${esc(x.photoUrl)}" alt="Photo of ${esc(x.name)}"></a>`:''}<div class="issue-actions-row"><label class="field">Status<select data-issue-status="${x.id}">${ISSUE_STATUSES.map(v=>`<option ${v===x.status?'selected':''}>${v}</option>`).join('')}</select></label><button type="button" class="danger-btn issue-delete-btn" data-delete-issue="${x.id}">Delete permanently</button></div><div class="issue-chat"><h4>Discussion</h4><div class="issue-messages" data-issue-messages="${x.id}">${x.messages.map(m=>`<div class="issue-message"><b>${esc(m.author||'Team member')}</b><span>${esc(m.text)}</span><small>${new Date(m.createdAt).toLocaleString()}</small></div>`).join('')||'<div class="empty-note">No messages yet.</div>'}</div><form data-issue-chat="${x.id}" class="issue-chat-form"><input data-issue-author value="${esc(currentAuthor())}" readonly><input data-issue-message placeholder="Add a thought or update" required><button class="mini-btn">Send</button></form></div></div>`:''}</div>`}
function issueFormHtml(){const locs=selectors.locations();return `<form id="issueForm" class="form-grid issue-form-grid modal-issue-form"><div class="field"><label>Location<select id="issueLocation" required><option value="">Choose location</option><option value="all">All locations</option>${locs.map(l=>`<option value="${l.id}">${esc(l.name)}</option>`).join('')}</select></label></div><div class="field wide"><label>Issue name<input id="issueName" required></label></div><div class="field full"><label>Description<textarea id="issueDescription" rows="4" required></textarea></label></div><div class="field full"><label>Photo<input id="issuePhoto" type="file" accept="image/*" capture="environment"></label><div class="task-sub">On a phone, this can open the camera.</div></div><div class="field full issue-assignee-field"><label>Assigned to</label><div data-issue-assignees>${issueAssigneeRows([''])}</div></div><div class="field full"><button id="saveIssueBtn" class="primary-btn">Document issue</button></div></form>`}
function renderIssues(){const r=$('issuesTab'),locs=visibleLocations();r.innerHTML=`<div class="section-card compact-section-head"><div class="section-head"><div><h2>Documented Issues</h2><p>Record campus problems, photos, assignments, status changes, and discussion.</p></div><button id="openDocumentIssue" class="primary-btn">Document Task</button></div></div><div class="section-card"><div class="locations-board">${locs.map(l=>`<div class="location-column"><div class="location-head"><div class="location-title"><span class="color-dot" style="background:${l.color}"></span>${esc(l.name)}</div></div>${selectors.issues().filter(x=>x.locationId===l.id).map(issueCard).join('')||'<div class="empty-note">No documented issues.</div>'}</div>`).join('')}</div></div>`;$('openDocumentIssue').onclick=()=>{const m=modal('Document Task',issueFormHtml());bindIssueAssignees(m);m.querySelector('#issueForm').onsubmit=saveIssue};document.querySelectorAll('[data-issue-expand]').forEach(b=>b.onclick=()=>{issueExpanded.has(b.dataset.issueExpand)?issueExpanded.delete(b.dataset.issueExpand):issueExpanded.add(b.dataset.issueExpand);renderIssues()});document.querySelectorAll('[data-issue-status]').forEach(x=>x.onchange=async()=>{const old=selectors.issueById(x.dataset.issueStatus)?.status||'Documented';if(x.value==='Dismiss'){const reason=prompt('Reason for dismissal:');if(reason===null||!reason.trim()){x.value=old;return}await actions.setIssueStatus(x.dataset.issueStatus,x.value,reason)}else if(x.value==='Completed'){if(!confirm('Mark this issue completed and move it to the hidden completed log?')){x.value=old;return}await actions.setIssueStatus(x.dataset.issueStatus,x.value)}else await actions.setIssueStatus(x.dataset.issueStatus,x.value);renderIssues()});document.querySelectorAll('[data-delete-issue]').forEach(b=>b.onclick=async()=>{if(!confirm('Permanently delete this issue? It will not be saved in a log.'))return;const issue=selectors.issueById(b.dataset.deleteIssue);if(issue?.photoPath)await deleteObject(ref(storage,issue.photoPath)).catch(()=>{});await actions.deleteIssue(b.dataset.deleteIssue);issueExpanded.delete(b.dataset.deleteIssue);renderIssues()});document.querySelectorAll('[data-issue-chat]').forEach(f=>f.onsubmit=async e=>{e.preventDefault();const msg=f.querySelector('[data-issue-message]').value;await actions.addIssueMessage(f.dataset.issueChat,msg,currentAuthor());renderIssues();requestAnimationFrame(()=>{const box=document.querySelector(`[data-issue-messages="${f.dataset.issueChat}"]`);if(box)box.scrollTop=box.scrollHeight})});requestAnimationFrame(()=>document.querySelectorAll('[data-issue-messages]').forEach(box=>box.scrollTop=box.scrollHeight))}
async function saveIssue(e){e.preventDefault();const form=e.currentTarget,btn=form.querySelector('#saveIssueBtn'),file=form.querySelector('#issuePhoto').files?.[0];btn.disabled=true;btn.innerHTML='<span class="spinner"></span> Saving…';try{let photoUrl='',photoPath='';if(file){const safe=file.name.replace(/[^a-zA-Z0-9._-]/g,'_');photoPath=`users/${auth.currentUser.uid}/documentedIssues/${Date.now()}-${safe}`;const rr=ref(storage,photoPath);await uploadBytes(rr,file,{contentType:file.type||'image/jpeg'});photoUrl=await getDownloadURL(rr)}const assignedTo=[...form.querySelectorAll('[data-issue-assignee]')].map(x=>x.value.trim()).filter(Boolean),selectedLocation=form.querySelector('#issueLocation').value,locationIds=selectedLocation==='all'?selectors.locations().map(l=>l.id):[selectedLocation],base={name:form.querySelector('#issueName').value,description:form.querySelector('#issueDescription').value,assignedTo,photoUrl,photoPath,status:'Documented',messages:[]};for(const locationId of locationIds)await actions.createIssue({...base,locationId});closeModal();renderIssues();toast(locationIds.length>1?'Independent issues added to all locations.':'Issue documented.','good')}catch(err){console.error(err);toast(err.message||'Could not save issue.','error');btn.disabled=false;btn.textContent='Document issue'}}
